selector_to_html = {"a[href=\"#path-to-save-your-files\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">1.5. </span>Path to save your files<a class=\"headerlink\" href=\"#path-to-save-your-files\" title=\"Permalink to this heading\">#</a></h2><p>We can save the assembled image or individual ROIs to disk. The currently supported file extensions are <code class=\"docutils literal notranslate\"><span class=\"pre\">.tiff</span></code> and <code class=\"docutils literal notranslate\"><span class=\"pre\">.zarr</span></code>.</p>", "a[href=\"#lbm-step-1-image-assembly\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">1. </span>LBM Step 1: Image Assembly<a class=\"headerlink\" href=\"#lbm-step-1-image-assembly\" title=\"Permalink to this heading\">#</a></h1><p>Raw ScanImage .tiff files are saved to disk in an interleaved manner.</p>", "a[href=\"#steps\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">1.1. </span>Steps:<a class=\"headerlink\" href=\"#steps\" title=\"Permalink to this heading\">#</a></h2><p><strong>1a.</strong> Set up filepaths.</p><p><strong>1b.</strong> Initialize a <a class=\"reference external\" href=\"https://github.com/atlab/scanreader/tree/master\">scanreader</a> object to read in raw .tiff files.</p>", "a[href=\"#input-data-path-to-your-raw-tiff-file-s\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">1.2. </span>Input data: Path to your raw .tiff file(s)<a class=\"headerlink\" href=\"#input-data-path-to-your-raw-tiff-file-s\" title=\"Permalink to this heading\">#</a></h2><p>Before processing, ensure:</p>", "a[href=\"#displaying-multiple-planes-with-fastplotlib\"]": "<h3 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">1.4.1. </span>Displaying multiple planes with Fastplotlib<a class=\"headerlink\" href=\"#displaying-multiple-planes-with-fastplotlib\" title=\"Permalink to this heading\">#</a></h3><p>When passing data into <a class=\"reference external\" href=\"https://fastplotlib.org/ver/dev/api/widgets/ImageWidget_api/fastplotlib.ImageWidget.html#fastplotlib-imagewidget\">ImageWidget()</a>, we need to transpose the <strong>slider dimensions</strong> to the first indices (i.e. <code class=\"docutils literal notranslate\"><span class=\"pre\">[T,</span> <span class=\"pre\">z,</span> <span class=\"pre\">...]</span></code> or <code class=\"docutils literal notranslate\"><span class=\"pre\">[T,</span> <span class=\"pre\">...]</span></code>) to display the movie correctly.</p><p>array.T will transpose the slider dimensions to the first indices, though it will also flip the image on its side.</p>", "a[href=\"#preview-the-scanreader-object\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">1.4. </span>Preview the scanreader object<a class=\"headerlink\" href=\"#preview-the-scanreader-object\" title=\"Permalink to this heading\">#</a></h2><p>The scanreader object contains the following attributes:</p>", "a[href=\"#include-more-z-planes-for-a-4d-graphic\"]": "<h3 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">1.4.3. </span>Include more z-planes for a 4D graphic<a class=\"headerlink\" href=\"#include-more-z-planes-for-a-4d-graphic\" title=\"Permalink to this heading\">#</a></h3>", "a[href=\"#initialize-a-scanreader-object\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">1.3. </span>1. Initialize a scanreader object<a class=\"headerlink\" href=\"#initialize-a-scanreader-object\" title=\"Permalink to this heading\">#</a></h2><p>(Option 1). Simply pass a string containing a wildcard pattern for files to gather</p>", "a[href=\"#view-a-single-z-plane-timeseries\"]": "<h3 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">1.4.2. </span>View a single z-plane timeseries<a class=\"headerlink\" href=\"#view-a-single-z-plane-timeseries\" title=\"Permalink to this heading\">#</a></h3>", "a[href=\"#read-back-in-your-file-to-make-sure-it-saved-properly\"]": "<h3 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">1.5.1. </span>Read back in your file to make sure it saved properly<a class=\"headerlink\" href=\"#read-back-in-your-file-to-make-sure-it-saved-properly\" title=\"Permalink to this heading\">#</a></h3>"}
skip_classes = ["headerlink", "sd-stretched-link"]

window.onload = function () {
    for (const [select, tip_html] of Object.entries(selector_to_html)) {
        const links = document.querySelectorAll(` ${select}`);
        for (const link of links) {
            if (skip_classes.some(c => link.classList.contains(c))) {
                continue;
            }

            tippy(link, {
                content: tip_html,
                allowHTML: true,
                arrow: true,
                placement: 'auto-start', maxWidth: 500, interactive: false,

            });
        };
    };
    console.log("tippy tips loaded!");
};
